        recvcounts::Ptr{MPI_Count},
        rdispls::Ptr{MPI_Aint},
        recvtypes::Ptr{MPI_Datatype},
        comm::MPI_Comm,
        info::MPI_Info,
        request::Ref{MPI_Request},
    )::Cint

- `sendbuf`: [in] starting address of send buffer
- `sendcounts`: [in] integer array (of length group size) specifying the number of elements to send to each \MPI/ process
- `sdispls`: [in] integer array (of length group size). Entry \mpicode{j} specifies the displacement in bytes (relative to \mpiarg{sendbuf}) from which to take the outgoing data destined for \MPI/ process \mpicode{j}
- `sendtypes`: [in] array of datatypes (of length group size). Entry \mpicode{j} specifies the type of data to send to \MPI/ process \mpicode{j}
- `recvbuf`: [out] address of receive buffer
- `recvcounts`: [in] integer array (of length group size) specifying the number of elements that can be received from each \MPI/ process
- `rdispls`: [in] integer array (of length group size). Entry \mpicode{i} specifies the displacement in bytes (relative to \mpiarg{recvbuf}) at which to place the incoming data from \MPI/ process \mpicode{i}
- `recvtypes`: [in] array of datatypes (of length group size). Entry \mpicode{i} specifies the type of data received from \MPI/ process \mpicode{i}
- `comm`: [in] communicator
- `info`: [in] info argument
- `request`: [out] communication request
"""
function MPI_Alltoallw_init_c(
    sendbuf::Cvoid,
    sendcounts::Vector{MPI_Count},
    sdispls::Vector{MPI_Aint},
    sendtypes::Vector{MPI_Datatype},
