    comm::MPI_Comm,
    info::MPI_Info,
    request::Union{Ref{MPI_Request},Ptr{MPI_Request}},
)
    retval = @ccall libmpi.MPI_Alltoallw_init_c(
        sendbuf::Cvoid,
        sendcounts::Ptr{MPI_Count},
